// src/components/imagenInteractiva.jsx
import React, { useState } from "react";

const ImagenInteractiva = ({ items, imagenDefault, ancho = "60vw" }) => {
  const [seleccionado, setSeleccionado] = useState(null);

  return (
    <div
      className="flex flex-col"
      style={{ width: ancho, aspectRatio: '4 / 3' }} // Proporción ajustada automáticamente
    >
      {/* Barra de iconos */}
      <div className="w-full bg-black flex justify-between items-center px-4 py-2">
        {items.map((item, index) => (
          <img
            key={index}
            src={item.icono}
            alt={`icono-${index}`}
            className="h-12 cursor-pointer hover:opacity-80"
            onClick={() => setSeleccionado(item)}
          />
        ))}
      </div>

      {/* Panel de contenido */}
      <div className="w-full bg-gray-100 text-black p-6 flex flex-col items-center gap-4 flex-grow overflow-auto">
        {seleccionado ? (
          <>
            <h2 className="text-xl font-bold text-center">{seleccionado.subtitulo}</h2>
            <img
              src={seleccionado.imagen}
              alt="contenido"
              className="max-w-full h-64 object-contain"
            />
            <p className="text-center max-w-2xl">{seleccionado.texto}</p>
          </>
        ) : (
          <img
            src={imagenDefault}
            alt="default"
            className="w-full h-96 object-contain"
          />
        )}
      </div>
    </div>
  );
};

export default ImagenInteractiva;
